using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- Setup: a source-gen context that only knows about Person ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = AppJsonContext.Default
};

// 1) Strongly-typed retrieval — returns JsonTypeInfo<Person> (no cast at the call-site)
JsonTypeInfo<Person> personInfo =
    (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));

Console.WriteLine($"Got typed metadata  : {personInfo.Type.Name}  (JsonTypeInfo<{personInfo.Type.Name}>)");

var json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Round-trip serialize : {json}");

Person? back = JsonSerializer.Deserialize(json, personInfo);
Console.WriteLine($"Round-trip deserialize: Name={back?.Name}, Age={back?.Age}");

// 2) Probe without throwing — TryGetTypeInfo returns false when metadata is absent
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
    Console.WriteLine($"\nTryGetTypeInfo(Person) => true  (type: {found!.Type.Name})");

if (!options.TryGetTypeInfo(typeof(Order), out _))
    Console.WriteLine("TryGetTypeInfo(Order)  => false — no metadata, no exception");

// --- Types ---------------------------------------------------------------
public record Person(string Name, int Age);
public record Order(int Id, decimal Total);   // deliberately NOT in the context

[JsonSerializable(typeof(Person))]
public partial class AppJsonContext : JsonSerializerContext;

